**5 Essential Security Measures:**

**1. Helmet - Security Headers:**
```javascript
const helmet = require('helmet');
app.use(helmet());
```
- Sets X-Frame-Options (prevents click-jacking)
- Sets X-XSS-Protection
- Sets Content-Security-Policy
- Removes X-Powered-By header
- Enforces HTTPS via HSTS

**2. Rate Limiting - Prevent Abuse:**
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // 100 requests per window
  message: { error: 'Too many requests' }
});

app.use('/api', limiter);
```
- Prevents brute force attacks
- Mitigates DDoS attacks
- Protects against API abuse

**3. Data Sanitization - Prevent Injection:**
```javascript
const mongoSanitize = require('express-mongo-sanitize');
const xss = require('xss-clean');

app.use(mongoSanitize());  // NoSQL injection
app.use(xss());            // XSS attacks
```
- Removes $ and . from req.body/params
- Escapes HTML entities
- Prevents script injection

**4. CORS - Control Access:**
```javascript
const cors = require('cors');

app.use(cors({
  origin: ['https://myapp.com'],
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE']
}));
```
- Controls which domains can access API
- Prevents unauthorized cross-origin requests
- Protects sensitive endpoints

**5. Request Size Limiting:**
```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));
```
- Prevents large payload attacks
- Limits memory consumption
- Protects against DoS via large bodies

**Complete Setup:**
```javascript
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const mongoSanitize = require('express-mongo-sanitize');
const xss = require('xss-clean');
const cors = require('cors');
const hpp = require('hpp');

app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGINS }));
app.use(rateLimit({ windowMs: 900000, max: 100 }));
app.use(express.json({ limit: '10kb' }));
app.use(mongoSanitize());
app.use(xss());
app.use(hpp());
```

